113	async fn api_scan(
114	    State(state): State<Arc<AppState>>,
115	    mut multipart: Multipart,
116	) -> Result<Json<ScanReply>, ApiError> {
117	    let tmp = tempfile::TempDir::new().map_err(|e| ApiError::internal(format!("tempdir: {e}")))?;
118	    let mut passwords: Vec<String> = Vec::new();
119	    let mut provider_name = String::from("none");
120	    let mut file_count = 0;
121	
122	    while let Some(mut field) = multipart
123	        .next_field()
124	        .await
125	        .map_err(|e| ApiError::bad_request(format!("multipart: {e}")))?
126	    {
127	        match field.name().unwrap_or("") {
128	            "wallet" => {
129	                let filename = field.file_name().unwrap_or("upload.bin").to_string();
130	                let safe = sanitize_filename(&filename);
