136	                    .chunk()
137	                    .await
138	                    .map_err(|e| ApiError::internal(format!("chunk: {e}")))?
139	                {
140	                    use tokio::io::AsyncWriteExt;
141	                    f.write_all(&chunk)
142	                        .await
143	                        .map_err(|e| ApiError::internal(format!("write: {e}")))?;
144	                }
145	                file_count += 1;
146	            }
147	            "passwords" => {
148	                let text = field
149	                    .text()
150	                    .await
151	                    .map_err(|e| ApiError::bad_request(format!("passwords: {e}")))?;
152	                passwords = text
153	                    .lines()
154	                    .map(|l| l.trim().to_string())
