168	    if file_count == 0 {
169	        return Err(ApiError::bad_request("no files uploaded".into()));
170	    }
171	
172	    let provider: Option<Box<dyn BalanceProvider>> = match ProviderKind::parse(&provider_name) {
173	        Ok(ProviderKind::Mock) => Some(Box::new(MockProvider {
174	            path: Some(state.mock_file.clone()),
175	        })),
176	        Ok(kind) => provider_from_kind(kind, None),
177	        Err(e) => return Err(ApiError::bad_request(e)),
178	    };
179	    let provider_label = provider.as_deref().map(|p| p.name().to_string());
180	
181	    let results = tokio::task::spawn_blocking({
182	        let root = tmp.path().to_path_buf();
183	        move || scan_path(&root, &passwords, provider.as_deref())
184	    })
185	    .await
186	    .map_err(|e| ApiError::internal(format!("join: {e}")))?;
