229	async fn api_mnemonic(Json(req): Json<MnemonicRequest>) -> Result<Json<MnemonicReply>, ApiError> {
230	    if req.phrase.trim().is_empty() {
231	        return Err(ApiError::bad_request("phrase is required".into()));
232	    }
233	    match req.kind.as_str() {
234	        "bip39" => {
235	            let keys = derive_bip39(
236	                req.phrase.trim(),
237	                &req.passphrase,
238	                req.gap_limit,
239	                DEFAULT_SPECS,
240	                "(mnemonic)",
241	            )
242	            .map_err(ApiError::bad_request)?;
243	            Ok(Json(MnemonicReply::Bip39 { keys }))
244	        }
245	        "blockchain" => {
246	            let path = req.wordlist.ok_or_else(|| {
247	                ApiError::bad_request("blockchain.com mnemonics require a wordlist path".into())
248	            })?;
249	            let text = std::fs::read_to_string(&path)
250	                .map_err(|e| ApiError::bad_request(format!("wordlist: {e}")))?;
251	            let words: Vec<String> = text
252	                .lines()
253	                .map(|l| l.trim().to_string())
254	                .filter(|l| !l.is_empty())
255	                .collect();
256	            let decoded = decode_mnemonic(req.phrase.trim(), &words)
257	                .map_err(|e| ApiError::bad_request(e.to_string()))?;
258	            Ok(Json(MnemonicReply::Blockchain {
259	                decoded: DecodedReply {
260	                    password: decoded.password,
261	                    word_count: decoded.word_count,
262	                    version: decoded.version_guess,
263	                },
264	            }))
265	        }
266	        other => Err(ApiError::bad_request(format!("unknown kind: {other}"))),
267	    }
268	}
