275	    let results = tokio::task::spawn_blocking(move || {
276	        scan_path(
277	            &dir,
278	            &["orpheus-demo".to_string()],
279	            Some(&provider as &dyn BalanceProvider),
280	        )
281	    })
282	    .await
283	    .map_err(|e| ApiError::internal(format!("join: {e}")))?;
284	    Ok(Json(ScanReply::new(results, Some("mock"))))
285	}
