289	async fn serve_static(uri: axum::http::Uri) -> Response {
290	    let path = uri.path().trim_start_matches('/');
291	    let path = if path.is_empty() { "index.html" } else { path };
292	    if let Some(asset) = Assets::get(path) {
293	        let mime = mime_guess::from_path(path).first_or_octet_stream();
294	        (
295	            StatusCode::OK,
296	            [(header::CONTENT_TYPE, mime.as_ref())],
297	            asset.data.into_owned(),
298	        )
299	            .into_response()
300	    } else if let Some(index) = Assets::get("index.html") {
301	        // SPA fallback
302	        (
303	            StatusCode::OK,
304	            [(header::CONTENT_TYPE, "text/html; charset=utf-8")],
305	            index.data.into_owned(),
306	        )
307	            .into_response()
308	    } else {
309	        (StatusCode::NOT_FOUND, "not found").into_response()
310	    }
311	}
312	
313	fn sanitize_filename(name: &str) -> String {
314	    name.rsplit('/')
315	        .next()
316	        .unwrap_or(name)
317	        .rsplit('\\')
318	        .next()
319	        .unwrap_or(name)
320	        .chars()
321	        .filter(|c| !matches!(c, '\0' | '\n' | '\r'))
322	        .collect::<String>()
323	}
324	
325	fn workspace_root() -> PathBuf {
326	    let here = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
327	    for ancestor in here.ancestors() {
328	        let cargo = ancestor.join("Cargo.toml");
329	        if cargo.exists()
330	            && std::fs::read_to_string(&cargo)
331	                .map(|t| t.contains("[workspace]"))
332	                .unwrap_or(false)
333	        {
334	            return ancestor.to_path_buf();
335	        }
336	    }
337	    here
338	}
339	
340	// ---- errors ----------------------------------------------------------------
341	
342	#[derive(Debug)]
343	struct ApiError {
344	    status: StatusCode,
345	    message: String,
346	}
347	
348	impl ApiError {
349	    fn bad_request(msg: String) -> Self {
350	        Self {
351	            status: StatusCode::BAD_REQUEST,
352	            message: msg,
353	        }
354	    }
355	    fn internal(msg: String) -> Self {
356	        Self {
357	            status: StatusCode::INTERNAL_SERVER_ERROR,
358	            message: msg,
359	        }
360	    }
361	}
362	
363	impl IntoResponse for ApiError {
364	    fn into_response(self) -> Response {
365	        (
366	            self.status,
367	            Json(serde_json::json!({ "error": self.message })),
368	        )
369	            .into_response()
370	    }
371	}
