213	fn render(results: &[WalletScanResult], fmt: OutputFormat, provider: Option<&str>) {
214	    match fmt {
215	        OutputFormat::Json => {
216	            let v = serde_json::json!({
217	                "results": results,
218	                "summary": ScanSummary::from_results(results, provider),
219	            });
220	            println!("{}", serde_json::to_string_pretty(&v).unwrap());
221	        }
222	        OutputFormat::Csv => {
223	            println!(
224	                "source_file,source_type,path,address,wif,received_sat,sent_sat,balance_sat,tx_count"
225	            );
226	            for r in results {
227	                for k in &r.keys {
228	                    println!(
229	                        "{},{},{},{},{},{},{},{},{}",
230	                        r.source_file,
231	                        r.source_type.as_str(),
232	                        k.derivation_path.as_deref().unwrap_or(""),
233	                        k.address_compressed,
234	                        k.wif,
235	                        k.total_received_sat.unwrap_or(0),
236	                        k.total_sent_sat.unwrap_or(0),
237	                        k.balance_sat.unwrap_or(0),
238	                        k.tx_count.unwrap_or(0),
239	                    );
240	                }
241	            }
242	        }
243	        OutputFormat::Table => render_table(results, provider),
244	    }
245	}
246	
247	fn sat_to_btc(sat: u64) -> String {
248	    format!("{:.8}", sat as f64 / 1.0e8)
249	}
250	
251	fn render_table(results: &[WalletScanResult], provider: Option<&str>) {
252	    let summary = ScanSummary::from_results(results, provider);
253	
254	    println!(
255	        "\n Orpheus scan: {} wallet(s), {} key(s)\n",
256	        summary.wallets, summary.total_keys,
257	    );
258	
259	    for r in results {
260	        println!("◆ {}  [{}]", r.source_file, r.source_type.as_str());
261	        if let Some(err) = &r.error {
262	            println!("  error: {err}");
263	            continue;
264	        }
265	        if r.keys.is_empty() {
266	            println!("  (no keys)");
267	            continue;
268	        }
269	
270	        let mut table = Table::new();
271	        table
272	            .load_preset(UTF8_FULL)
273	            .apply_modifier(UTF8_ROUND_CORNERS)
274	            .set_header(vec![
275	                "path", "address", "received", "sent", "balance", "txs", "WIF",
276	            ]);
277	
278	        let mut sorted: Vec<_> = r.keys.iter().collect();
279	        // Primary sort: current balance. Secondary: anything ever received.
280	        sorted.sort_by_key(|k| {
281	            std::cmp::Reverse((
282	                k.balance_sat.unwrap_or(0),
283	                k.total_received_sat.unwrap_or(0),
284	            ))
285	        });
286	        let show_all = sorted
287	            .iter()
288	            .all(|k| k.balance_sat.unwrap_or(0) == 0 && k.total_received_sat.unwrap_or(0) == 0);
289	        for k in sorted.iter().take(if show_all { 5 } else { usize::MAX }) {
290	            let seen = k.balance_sat.unwrap_or(0) != 0 || k.total_received_sat.unwrap_or(0) != 0;
291	            if !show_all && !seen {
292	                continue;
293	            }
294	            let wif = if k.wif.len() > 16 {
295	                format!("{}…{}", &k.wif[..8], &k.wif[k.wif.len() - 4..])
296	            } else {
297	                k.wif.clone()
298	            };
299	            table.add_row(vec![
300	                Cell::new(k.derivation_path.clone().unwrap_or_else(|| "-".into())),
301	                Cell::new(&k.address_compressed),
